import sys
class Solution:
    def solve(self, nums: list[int]) -> bool:
        n = int(nums[0])
        if n <= 1:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

if __name__ == '__main__':
    n = int(input("\n"))
    print(Solution().solve([str(n)]))

